import{_ as e,o as l,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260512/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/6261_久元/20260512/F17_籌碼分佈與法人動態分析.md"}'),r={name:"審計報告庫/財務審計/6261_久元/20260512/F17_籌碼分佈與法人動態分析.md"};function o(n,a,h,s,d,c){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="f17-籌碼分佈與法人動態分析-財務審計專家報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 財務審計專家報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-財務審計專家報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>三大法人的持股動向與資金流向趨勢為何？技術面與籌碼面是否透露異常訊號？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2025法人賣超119.7萬股。2026外資+145自營避險+397萬(被動)投信缺席。法人由空轉多但量能有限</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2026年5月11日法人買賣超</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：2025法人合計賣超-119.7萬股(外資-52+投信-80+自營+12)。2026外資轉買+145萬、自營避險+397萬(被動非主動)。外資持股9-10%遠低同業(京元30-40%)。投信2025賣超80萬股後2026零買賣。法人參與度偏低反映市場對久元獲利前景持謹慎保守態度。</li><li><strong>診斷見解</strong>：法人由空轉多但量能有限且結構脆弱—自營避險被動買盤佔比過高，投信完全缺席，若無EPS實質改善法人買盤難持續放大，籌碼面缺乏強勢主力。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="法人流向" tabindex="-1">法人流向 <a class="header-anchor" href="#法人流向" aria-label="Permalink to &quot;法人流向&quot;">​</a></h3><p>2025法人合計賣超119.7萬股(佔股本0.93%)，股價65→85元但法人趁漲出貨。2026轉買超531萬股(4.1%)但自營避險397萬為被動扣除後外資僅145萬(~1.2億)。法人尚未形成強烈多頭共識。</p><h3 id="外資持股" tabindex="-1">外資持股 <a class="header-anchor" href="#外資持股" aria-label="Permalink to &quot;外資持股&quot;">​</a></h3><p>外資持股9-10%在半導體股中偏低(京元30-40%精測20-25%)。低持股代表關注度有限但加碼空間大。投信完全缺席(2025賣80萬後2026零買賣)。本土機構對久元興趣有限。</p><h3 id="籌碼面綜合" tabindex="-1">籌碼面綜合 <a class="header-anchor" href="#籌碼面綜合" aria-label="Permalink to &quot;籌碼面綜合&quot;">​</a></h3><p>融資2,500-3,500張(使用率10-14%)週轉率&lt;1.5%無異常。特徵為法人冷淡與散戶支撐—股價85元PER 29倍為散戶撐盤格局。下跌時法人+散戶遞迴強化可能加速跌幅。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點" tabindex="-1">🔴 空方觀點 <a class="header-anchor" href="#🔴-空方觀點" aria-label="Permalink to &quot;🔴 空方觀點&quot;">​</a></h3><ol><li>投信2025賣超80萬股後2026零買賣—本土機構風向標完全缺席，基金經理解讀為估值偏高成長動能不足，法人關注度低迷不利籌碼面</li><li>外資+145萬股僅約1.2億元不足以撐起成交值區間，若無實質利多法人買盤難持續，外資持股率低迷僅9%顯示持續性不足</li><li>自營避險397萬為被動部位，隨權證到期減倉可能轉賣壓，2026年流向結構脆弱易逆轉</li></ol><h3 id="🟢-多方觀點" tabindex="-1">🟢 多方觀點 <a class="header-anchor" href="#🟢-多方觀點" aria-label="Permalink to &quot;🟢 多方觀點&quot;">​</a></h3><ol><li>2026年法人已由空轉多，年度淨買超531萬vs 2025的-120萬大幅改善</li><li>外資持股僅9-10%遠低同業，若EPS重返2元外資可大幅加碼(回補至20%將買約1,400萬股)</li><li>大股東47%+散戶17%+法人10%，法人進出影響小於大股東穩定持有</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>法人參與度偏低—投信缺席、外資持股率低。2026流向轉正向但量能有限。最大風險在缺乏強勢法人買盤的散戶主導格局。觀察EPS改善能否吸引投信進場。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>原始數據：FinMind TaiwanStockInstitutionalBuySell</li><li>數據查詢日期：2026-05-12</li></ul>',23)])])}const b=e(r,[["render",o]]);export{_ as __pageData,b as default};
